#!/usr/bin/env node
// Sync Folo subscription export into DailyAna RSS feeds.
//
// Input:
//   config/folo-subscriptions.json generated by:
//   cmd /c "npx.cmd --yes folocli@latest --format json subscription list > config\folo-subscriptions.json"

import fs from "node:fs"
import path from "node:path"

const DEFAULT_RSSHUB_BASE = "https://rsshub.app"

const args = process.argv.slice(2)

const readArg = (name, fallback) => {
  const index = args.indexOf(name)
  if (index === -1 || !args[index + 1]) return fallback
  return args[index + 1]
}

const hasArg = (name) => args.includes(name)

const exportPath = readArg("--export", "config/folo-subscriptions.json")
const configPath = readArg("--config", "config/config.yaml")
const rsshubBase = readArg("--rsshub-base", DEFAULT_RSSHUB_BASE).replace(/\/+$/, "")
const disableErrorFeeds = hasArg("--disable-error-feeds")

const yamlString = (value) => JSON.stringify(value || "")

const normalizeFeedUrl = (url) => {
  if (url.startsWith("rsshub://")) {
    return `${rsshubBase}/${url.slice("rsshub://".length).replace(/^\/+/, "")}`
  }
  return url
}

const payload = JSON.parse(fs.readFileSync(exportPath, "utf8"))
const subscriptions = payload?.data?.subscriptions || []

const seenUrls = new Set()
const foloFeeds = []

for (const item of subscriptions) {
  const feed = item.feeds || {}
  if (!feed.url) continue

  const url = normalizeFeedUrl(feed.url)
  if (seenUrls.has(url)) continue
  seenUrls.add(url)

  const feedId = String(item.feedId || feed.id || foloFeeds.length + 1)
  const title = item.title || feed.title || feedId
  const hasError = Boolean(feed.errorMessage)

  foloFeeds.push({
    id: `folo-${feedId}`,
    name: String(title),
    url,
    enabled: !(disableErrorFeeds && hasError),
  })
}

if (foloFeeds.length === 0) {
  console.error(`No feed subscriptions found in ${exportPath}`)
  process.exit(1)
}

const splitExistingFeedChunks = (feedBlock) => {
  const chunks = []
  let current = []

  for (const line of feedBlock) {
    if (/^  -\s+/.test(line)) {
      if (current.length > 0) chunks.push(current)
      current = [line]
    } else if (current.length > 0) {
      current.push(line)
    }
  }

  if (current.length > 0) chunks.push(current)
  return chunks
}

const isFoloChunk = (chunk) => {
  const first = (chunk[0] || "").trim()
  return first.startsWith("- id: folo-") || first.startsWith('- id: "folo-')
}

const renderFoloFeeds = (feeds) => {
  const lines = []
  for (const feed of feeds) {
    lines.push(`  - id: ${feed.id}`)
    lines.push(`    name: ${yamlString(feed.name)}`)
    lines.push(`    url: ${yamlString(feed.url)}`)
    lines.push(`    enabled: ${feed.enabled ? "true" : "false"}`)
  }
  return lines
}

const configText = fs.readFileSync(configPath, "utf8")
const lines = configText.split(/\r?\n/)

const feedsIndex = lines.findIndex((line) => line === "  feeds:")
if (feedsIndex === -1) {
  console.error("Could not find `rss.feeds` in config.yaml")
  process.exit(1)
}

let endIndex = lines.length
for (let index = feedsIndex + 1; index < lines.length; index += 1) {
  const line = lines[index]
  if (line && !line.startsWith(" ")) {
    endIndex = index
    break
  }
}

const existingBlock = lines.slice(feedsIndex + 1, endIndex)
const existingChunks = splitExistingFeedChunks(existingBlock)
const preservedLines = existingChunks.filter((chunk) => !isFoloChunk(chunk)).flat()

const newBlock = ["  feeds:", ...preservedLines, ...renderFoloFeeds(foloFeeds)]
const updated = [...lines.slice(0, feedsIndex), ...newBlock, ...lines.slice(endIndex)].join("\n")

const backupPath = `${configPath}.bak`
fs.copyFileSync(configPath, backupPath)
fs.writeFileSync(configPath, updated.endsWith("\n") ? updated : `${updated}\n`, "utf8")

console.log(`Synced ${foloFeeds.length} Folo feeds into ${configPath}`)
console.log(`Backup written to ${backupPath}`)
console.log(`RSSHub base: ${rsshubBase}`)

